import numpy as np
import tensorflow as tf
from sklearn import datasets, metrics, model_selection, preprocessing
# Load the data
data = np.genfromtxt('input.csv', delimiter=',')
# Train/Test Split
(trainX, trainY), (testX, testY) = model_selection.train_test_split(data[1:], data[0])
# Preprocess input features to a 32x32 greyscale image with max pixel value of 256 and min pixel value -256.
trainX = preprocessing.MinMaxScaler((-1,1)).fit_transform((trainX/np.max(np.abs(trainX))))
testX = preprocessing.MinMaxScaler((-1,1)).fit_transform((testX/np.max(np.abs(testX))))
trainY = trainY / 256 # Normalize training labels to a range of 0 and 1 by dividing them by max pixel value in the image.
testY = testY / 256 # Normalize testing labels as above.
# Create Placeholders for input features & Training Labels.
X = tf.placeholder(tf.float32, [None, 3], 'X')
Y = tf.placeholder(tf.int16,[None])
# Create variables to store trained model weights and biases. These will be updated by our optimizer during training.
W = tf.Variable(np.zeros((4,)), name='weight_model', dtype=tf.float32)
b = tf.Variable(0.,name="bias",dtype=tf.int16 ) # we're using float32 as our weight matrix is 3x4, so 4 bias values for each image. b is a scalar here, and its value will be adjusted by optimizer to ensure that the predicted value of Y (our output) matches up with Y(label).
# Predicts y_pred (prediction of our model based on the inputs in X. This equation gets minimized during training.)
y_pred = tf.nn.softmax((tf.tensordot(X,W)+b)) # tf.tensordot is matrix multiplication with W as weights.
# Loss function. We will get the prediction by using the above model (predicts y_pred) and we will compare them to actual values in our training labels Y (which contains labels for training set images). Since Y is an 8 bit unsigned integer, we will convert it into one hot representation with tf.oneHot() function
onehotlabels = tf.one_hot(indices=tf.cast(Y,'int32'),depth=510) # depth of one-hot matrix - 4. One-hot vector will have 8 elements, with 4th element having maximum value as 1 and rest 3 elements set to zero.
loss = tf.losses.mean_squared_error(labels=onehotlabels,predictions=y_pred) # Our loss function will be a mean square error (MSE), since our input values are normalized in the range of -1 to +1. MSE is good for regression problems, since it gives an average value for how much wrong we were at each point when predicting.
# Optimization
# We use Gradient Descent algorithm as optimizer here. It minimizes loss function by following these steps:
optimizer = tf.train.GradientDescentOptimizer(0.5).minimize(loss) # 0.5 is the learning rate for this particular iteration. Loss will be decreased in each step during optimization. Since we are using gradient descent optimizer, the weights (W & B values) will be adjusted by this formula - W - 0.5 * d/dW (the derivative of loss function with respect to W), and similarly for b. We repeat this process until convergence criteria is met.
# Actual prediction by running our model on test inputs. The actual value of Y will be the index of the maximum entry in each row after applying softmax on y_pred. Since one hot encoding has been used, the predicted values should always be less than 510 for our current dataset. We also need to convert our testY values into onehot representation with depth set to 32 (corresponding to number of labels).
correctPredictions = tf.equal(tf.argmax(y_pred), Y) # argmax is used incase you want the predicted class which has highest probability for each row after softmax function. We want our model to output the maximum value at that point, but not the values as one hot vectors (onehot labels)
accuracy = tf.reduce_mean(tf.cast(correctPredictions,'float')) # Accuracy will be a mean of 1s and 0s generated by comparing predicted vs label outputs. These one hot encoded labels can actually come in decimal range, so we must cast the binary array back to float type. We reduce this across the row axis as it returns an array of 510 average accuracy values for each row/sample in our testing set.
# Create session and initialize variables.
init = tf.global_variables_initializer() # Variables are created before initialization, so we need to do that first. The initialization method initializes all variables within a graph.
sess = tf.Session(graph=tf.get_default_graph())
sess.run(init)
# Begin Training Model
for i in range(10):
    _, l, accuracyValue = sess.run([optimizer, loss, accuracy], feed_dict={X: trainX, Y: np.argmax(trainY,axis=1)}) # We pass our data set inputs X to the model and labels (one hot representation of training Y) to optimizer. Accuracy will be evaluated by running our predictions on our test images in each iteration.
    print ('Iteration %d; loss=%f accuracy = %f' %(i+1,l,accuracyValue))
sess.close()